import { Web3Storage } from "web3.storage";

const GATEWAY_URL =
  process.env.REACT_APP_IPFS_GATEWAY || "https://ipfs.io/ipfs/";

export function hasIPFSSupport() {
  return Boolean(process.env.REACT_APP_WEB3STORAGE_TOKEN);
}

function makeStorageClient() {
  const token = process.env.REACT_APP_WEB3STORAGE_TOKEN;
  if (!token) {
    throw new Error(
      "IPFS client not configured. Set REACT_APP_WEB3STORAGE_TOKEN in your .env.",
    );
  }
  return new Web3Storage({ token });
}

export async function uploadTextToIPFS(text) {
  if (!hasIPFSSupport()) {
    // Graceful fallback: caller can decide to store text directly on-chain
    return null;
  }
  const client = makeStorageClient();
  const blob = new Blob([text], { type: "text/plain" });
  const file = new File([blob], "note.txt", { type: "text/plain" });
  const cid = await client.put([file], { wrapWithDirectory: false });
  return cid;
}

export async function fetchTextFromIPFS(cid) {
  if (!cid || !hasIPFSSupport()) return "";
  const url = `${GATEWAY_URL}${cid}`;
  const res = await fetch(url);
  if (!res.ok) {
    throw new Error(`Failed to fetch from IPFS gateway: ${res.status}`);
  }
  return await res.text();
}
